// Continuation-chain kickoff/step. lesson_id from parent (W_Master/manual). lang_index =
// which language to process this hop (default 0 = start of chain). The chain advances by
// W3 calling this dispatcher back with the next index when a language finishes.
const incoming = $input.first()?.json || {};
const lesson_id = incoming.lesson_id || null;
const lang_index = Number(incoming.lang_index) || 0;
return [{ json: { lesson_id, lang_index } }];

// Check Abort — cooperative kill switch for the W3 per-language continuation chain.
// Sits between Read Config and the "Aborted?" IF in W3 Dispatch. The dispatcher is re-entered
// once per language (this is where the multi-hour run actually spends its time), so this is
// the checkpoint that matters most.
//
// Stop semantics: W_Master writes localization_run_token at run start; the Slack stop button
// (via W_Abort) writes localization_abort_token = that same run_token. When the two match,
// the operator asked to stop THIS run. We emit a single sentinel item with an `aborted` flag so
// the downstream IF routes: true → post "✅ Локалізацію зупинено" (the confirmation the operator
// awaits) and halt; false → Resolve Lang → Fire W3 (chain continues).
//
// Because Execute W3 enters here at lang_index 0, a stop clicked during W1/W2 is also honored.
// The confirmation fires exactly once — on the hop where the halt is detected — and by then
// nothing of this run is running (the dispatcher runs after W2; the prior language already
// reached Save Full to Drive), so it genuinely means "safe to start a new run".
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const runToken = (cfg.localization_run_token || '').toString().trim();
const abortToken = (cfg.localization_abort_token || '').toString().trim();
const aborted = !!(runToken && abortToken && abortToken === runToken);

const p = $('Get Params').first().json || {};
if (aborted) {
  console.log(`W3 Dispatch: stop confirmed for run ${runToken} — halting chain at lang_index=${p.lang_index} (lesson ${p.lesson_id})`);
}

return [{ json: { aborted, run_token: runToken, lesson_id: p.lesson_id, lang_index: p.lang_index } }];

// W3 Dispatch — Build Stopped Slack. Posts the confirmation the operator awaits after pressing
// Stop: the cooperative kill-switch has actually halted the continuation chain (vs W_Abort's
// click-time "зупиняю…" message). Fired from the Aborted?=true branch, exactly once.
//
// Reads:
//   $('Read Config').all()     — slack_channel
//   $('Check Abort').first()   — lesson_id (sentinel)
// Emits { channel, text } for the native Slack node. Returns [] if slack_channel is unset.
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const channel = cfg.slack_channel;
if (!channel) { console.log('W3 Dispatch: slack_channel missing — skipping stop confirmation'); return []; }

const s = $('Check Abort').first().json || {};
const lines = [
  ':white_check_mark: *Localization stopped — confirmed*',
  '',
  `*Lesson:* ${s.lesson_id || '—'}`,
  'All processes finished. Safe to start a new run.',
];
return [{ json: { channel, text: lines.join('\n') } }];

// Resolve langs[lang_index] from config active_langs and hand W3 an explicit single lang +
// the flags it needs to (a) gate Slack to the final language and (b) chain to the next one.
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });
const langs = (cfg.active_langs || 'de,es,fr,it,pl,pt,tr').split(',').map(s => s.trim()).filter(Boolean);
if (!langs.length) throw new Error('active_langs produced empty list — check config');
const { lesson_id, lang_index } = $('Get Params').first().json;
const idx = Math.min(Math.max(lang_index, 0), langs.length - 1);
return [{ json: {
  lesson_id,
  lang: langs[idx],
  is_last_lang: idx === langs.length - 1,
  next_index: idx + 1,
} }];
